<body>
<!-- Hidden Source -->
<div id="src-data" style="display:none;">$1</div>

<div class="sys-container">
  <!-- System Header -->
  <div class="sys-header" onclick="this.parentElement.classList.toggle('collapsed')">
    <div class="sys-title"><i class="fas fa-biohazard"></i> LAB-13 <span style="font-size:0.7em; opacity:0.6; margin-left:5px">MONITOR</span></div>
    <div class="toggle-btn"><i class="fas fa-caret-down"></i></div>
  </div>

  <div class="sys-body">
    <!-- Status Bar -->
    <div class="info-bar">
      <span id="dsp-loc"><i class="fas fa-map-marker-alt"></i> N/A</span>
      <span id="dsp-time">--/-- 00:00 <i class="far fa-clock"></i></span>
    </div>

    <!-- Cards Container -->
    <div class="viewport" id="card-dock"></div>

    <!-- Navigation -->
    <div class="dock" id="nav-dock"></div>
  </div>
</div>

<script>
// Configurations
const CFG = {
  parts: ['乳房','阴蒂','阴道','后穴','口腔','子宫','尿道','皮肤'],
  icons: ['fa-bullseye','fa-toggle-on','fa-droplet','fa-circle-notch','fa-lips','fa-person-pregnant','fa-water','fa-hand-sparkles'],
  chars: ['真那', '纱织', '文子', '涅莉丝','玩家' ], // Output order keys
  meta: {
    '玩家': { name: 'Dr.{{user}}', role: 'ADMIN', img: 'usr', c: '#05d9e8' },
    '文子': { name: '九条文子', role: 'Rose', img: 'https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMS9xpNYYBb7_Lej3XV-lhOMg39A4jogACmR8AAtFAsVWvYcXQBwnHHzYE.jpg', c: '#ffcc00' },
    '纱织': { name: '月雾纱织', role: 'Shield', img: 'https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMS9ppNYX-y9ohG1LrHlMLgLkrUFJnhgAClh8AAtFAsVUxsgXlGfbvrDYE.jpg', c: '#d300c5' },
    '真那': { name: '月雾真那', role: 'Star', img: 'https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMS9tpNYX-4RJZOFZuWH7eO7OMTBThSwAClx8AAtFAsVWvxbB9nU8p0DYE.jpg', c: '#ff2a6d' },
    '涅莉丝': { name: '涅莉丝', role: 'Support', img: 'https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMS9hpNYX8zxtudcrm_nK-Xshj711fOAAClB8AAtFAsVVRdATobKB6LDYE.png', c: '#eee' }
  }
};

const $ = (s) => document.querySelector(s);
const safeRgx = (txt, rgx) => { const m = txt.match(rgx); return m ? m[1].trim() : 'N/A'; };
const toList = (str) => (str && str !== 'N/A') ? str.split(/[,，]/).map(s => s.trim()) : [];

function init() {
  const raw = $('#src-data').innerText;
  const cards = $('#card-dock');
  const docks = $('#nav-dock');

  // Clean container
  cards.innerHTML = ''; docks.innerHTML = '';

  // 1. Global Info
  const time = safeRgx(raw, /时间[:：](.*?)(?:\||\n|$)/);
  const date = safeRgx(raw, /日期[:：](.*?)(?:\||\n|$)/);
  const loc = safeRgx(raw, /地点[:：](.*?)(?:\||\n|$)/);
  $('#dsp-time').innerHTML = `${date} ${time} <i class="far fa-clock"></i>`;
  $('#dsp-loc').innerHTML = `<i class="fas fa-map-marker-alt"></i> ${loc}`;

  // 2. Process Characters
  let isFirst = true;

  CFG.chars.forEach((key, idx) => {
    // Regex matches: [Name:Title] Content [/Name]
    const rgx = new RegExp(`\\[${key}[:](.*?)\\]([\\s\\S]*?)\\[\\/${key}\\]`);
    const match = raw.match(rgx);
    const meta = CFG.meta[key];

    // Create DOCK item regardless of data presence (to keep UI consistent)
    const isAct = isFirst && match;
    const dItem = document.createElement('div');
    dItem.className = `dock-item ${isAct ? 'active' : ''}`;
    dItem.dataset.tip = meta.name;
    dItem.onclick = () => switchTab(key);
    dItem.id = `dock-${key}`;
    dItem.innerHTML = meta.img === 'usr' ? `<div class="user_avatar"></div>` : `<img src="${meta.img}">`;
    docks.appendChild(dItem);

    // Create CARD item
    const cItem = document.createElement('div');
    cItem.className = `card-box ${isAct ? 'active' : ''}`;
    cItem.id = `card-${key}`;

    if (match) {
      if(isAct) isFirst = false;
      const title = match[1];
      const txt = match[2];

      const mood = safeRgx(txt, /想法[:：](.*?)(\n|$)/);
      const state = safeRgx(txt, /状态[:：](.*?)(?:\||\/|\n)/); // Player uses "精力" but we map dynamically?
      const outfit = safeRgx(txt, /服装[:：](.*?)(?:\||\n)/);

      // Player Special Fields
      let tagHtml = '';
      if(key === '玩家') {
        const energy = safeRgx(txt, /精力[:：](.*?)(\||$)/);
        const equip = safeRgx(txt, /装备[:：](.*?)(\||$)/);
        tagHtml = `<span class="tag warn">${energy}</span><span class="tag">${equip}</span>`;
      } else {
        tagHtml = `<span class="tag warn">${state}</span><span class="tag">${outfit}</span>`;
      }

      // Body Grid Construction
      let gridHtml = '';
      if (key !== '玩家') {
        const lvStr = safeRgx(txt, /身体[:：](.*?)(\n|$)/);
        const stStr = safeRgx(txt, /部位状态[:：](.*?)(\n|$)/);
        const eqStr = safeRgx(txt, /部位装备[:：](.*?)(\n|$)/);

        const lvs = toList(lvStr).map(Number);
        const sts = toList(stStr);
        const eqs = toList(eqStr);

        gridHtml = `<div class="body-grid">`;
        CFG.parts.forEach((pName, i) => {
          const lv = lvs[i] || 0;
          const status = sts[i] || '-';
          const equip = eqs[i] || '无';
          const hasEquip = equip !== '无' && equip !== 'N/A';

          gridHtml += `
            <div class="body-cell lv-${lv}" style="--c:${CFG.meta[key].c}">
              <div class="cell-header"><span>${pName}</span><span class="cell-lv">Lv.${lv}</span></div>
              <div class="cell-icon"><i class="fas ${CFG.icons[i]}"></i></div>
              <div class="cell-stat" title="${status}">${status}</div>
              <div class="cell-equip" title="${equip}" style="color:${hasEquip?'#05d9e8':'#666'}">${hasEquip ? equip : '未装备'}</div>
            </div>`;
        });
        gridHtml += `</div>`;
      }

      const avaHtml = meta.img === 'usr' ? `<div class="user_avatar"></div>` : `<img src="${meta.img}" class="avatar-img">`;

      cItem.innerHTML = `
        <div class="card-top">
          <div class="avatar-wrap">${avaHtml}</div>
          <div class="info-wrap">
            <div class="char-name">${meta.name}</div>
            <div class="char-role">${title}</div>
            <div class="char-tags">${tagHtml}</div>
          </div>
        </div>
        <div class="mind-log"><i class="far fa-comment-dots"></i> ${mood}</div>
        ${gridHtml}
      `;
    } else {
      cItem.innerHTML = `<div style="text-align:center;padding:50px;color:#555">LINK OFFLINE</div>`;
    }
    cards.appendChild(cItem);
  });
}

window.switchTab = (k) => {
  document.querySelectorAll('.dock-item').forEach(d => d.classList.remove('active'));
  document.querySelectorAll('.card-box').forEach(c => c.classList.remove('active'));
  $(`#dock-${k}`).classList.add('active');
  const card = $(`#card-${k}`);
  card.classList.add('active');
  card.style.animation = 'none'; card.offsetHeight; card.style.animation = null; // Replay anim
};

setTimeout(init, 50);
</script>
</body>
</html>
